import{_ as i,o as e,c as l,a2 as r}from"./chunks/framework.BwNZcjNV.js";const g=JSON.parse('{"title":"IBS: IBS 워크스페이스 (Workspace)","description":"","frontmatter":{},"headers":[],"relativePath":"index.md","filePath":"index.md","lastUpdated":1784197842000}'),t={name:"index.md"};function n(o,a,s,h,d,u){return e(),l("div",null,[...a[0]||(a[0]=[r('<h1 id="ibs-ibs-워크스페이스-workspace" tabindex="-1">IBS: IBS 워크스페이스 (Workspace) <a class="header-anchor" href="#ibs-ibs-워크스페이스-workspace" aria-label="Permalink to &quot;IBS: IBS 워크스페이스 (Workspace)&quot;">​</a></h1><p><strong>IBS 워크스페이스</strong>는 부동산 개발사업의 전 과정에서 발생하는 자금, 계약, 고객, 문서, 소송 등 핵심 데이터를 통합 관리하고 협업하는 <strong>디벨로퍼를 위한 업무 공간</strong>입니다.</p><p>글로벌 협업 표준인 <strong>레드마인(Redmine)</strong> 엔진을 기반으로 설계된 <strong>IBS 워크스페이스</strong>는 단순한 데이터 기록을 넘어, 모든 업무 프로세스를 <strong>&#39;업무(Issue)&#39; 중심으로 연결</strong>합니다. 이를 통해 팀원들 간의 업무 공유 및 소통을 원활하게 하고, 모든 의사결정의 근거를 체계적으로 자산화합니다.</p><h2 id="왜-ibs-워크스페이스인가" tabindex="-1">왜 IBS 워크스페이스인가? <a class="header-anchor" href="#왜-ibs-워크스페이스인가" aria-label="Permalink to &quot;왜 IBS 워크스페이스인가?&quot;">​</a></h2><p>부동산 개발사업은 상품 유형(공동주택, 상가, 오피스 등)과 사업 방식(일반분양, 조합, 임대 등)에 따라 업무 프로세스가 매우 복잡합니다. 따라서 <strong>정확한 데이터와 체계적인 협업을 바탕으로 한 신속한 의사결정</strong>이 사업의 성패를 좌우합니다.</p><p><strong>IBS 워크스페이스</strong>는 이러한 복잡함을 걷어내고, 사용자가 데이터와 의사결정에 더욱 집중할 수 있는 직관적인 업무 환경을 제공합니다.</p><ul><li><strong>친숙한 협업 환경</strong> - 레드마인 기반의 이슈 트래킹으로 업무의 생성부터 완료까지 체계적으로 관리합니다.</li><li><strong>통합된 데이터 관리</strong> - 분양 계약, 수납, 회계 등 핵심 데이터를 하나의 워크스페이스에서 서로 연결하여 관리합니다.</li><li><strong>의사결정의 자산화</strong> - 모든 업무와 계약, 수지 데이터에 담당자의 논의 이력을 함께 기록하여 조직의 지식 자산으로 축적됩니다.</li><li><strong>신속한 의사결정</strong> - 실시간 대시보드를 통해 사업 수지와 자금 현황을 한눈에 파악할 수 있습니다.</li></ul><h2 id="주요-기능" tabindex="-1">주요 기능 <a class="header-anchor" href="#주요-기능" aria-label="Permalink to &quot;주요 기능&quot;">​</a></h2><h3 id="🎯-이슈-기반-협업-관리-redmine-engine" tabindex="-1">🎯 이슈 기반 협업 관리 (Redmine Engine) <a class="header-anchor" href="#🎯-이슈-기반-협업-관리-redmine-engine" aria-label="Permalink to &quot;🎯 이슈 기반 협업 관리 (Redmine Engine)&quot;">​</a></h3><ul><li>프로젝트별 업무 게시판 및 부서 간 협업 프로세스 운영</li><li>업무 히스토리 추적을 통한 지식 자산화</li><li>사용자별 맞춤형 업무 할당 및 알림 기능</li></ul><h3 id="🏗️-사업지-및-마스터플랜-설정" tabindex="-1">🏗️ 사업지 및 마스터플랜 설정 <a class="header-anchor" href="#🏗️-사업지-및-마스터플랜-설정" aria-label="Permalink to &quot;🏗️ 사업지 및 마스터플랜 설정&quot;">​</a></h3><ul><li>프로젝트 유형별 상세 속성 및 유닛 타입 정의</li><li>동·호수 배치 및 층별 공급가 관리</li><li>계약 회차 및 고지 조건 설정</li></ul><h3 id="🗺️-토지-매입-및-토지주-관리" tabindex="-1">🗺️ 토지 매입 및 토지주 관리 <a class="header-anchor" href="#🗺️-토지-매입-및-토지주-관리" aria-label="Permalink to &quot;🗺️ 토지 매입 및 토지주 관리&quot;">​</a></h3><ul><li>필지별 소유자 정보 및 소유 현황 관리</li><li>토지주 상담, 협의 및 계약 진행 이력 관리</li><li>매입 계약 체결 및 대금 집행 현황 관리</li></ul><h3 id="🤝-분양-계약-및-고객-관리-crm" tabindex="-1">🤝 분양 계약 및 고객 관리 (CRM) <a class="header-anchor" href="#🤝-분양-계약-및-고객-관리-crm" aria-label="Permalink to &quot;🤝 분양 계약 및 고객 관리 (CRM)&quot;">​</a></h3><ul><li>분양 계약자 정보 통합 등록 및 관리</li><li>유닛 매칭 및 동·호수별 분양 상태 시각화</li><li>해약, 승계 및 부적격자 관리 로직 지원</li></ul><h3 id="💰-자금-수납-및-회계-연동" tabindex="-1">💰 자금 수납 및 회계 연동 <a class="header-anchor" href="#💰-자금-수납-및-회계-연동" aria-label="Permalink to &quot;💰 자금 수납 및 회계 연동&quot;">​</a></h3><ul><li>계약별 납부 일정 및 수납 내역 관리</li><li>수납 확인서 발행 및 연체료 자동 계산</li><li>수납 데이터를 회계 시스템과 연동하여 반영</li></ul><h3 id="📊-사업-수지-분석-및-예산-통제" tabindex="-1">📊 사업 수지 분석 및 예산 통제 <a class="header-anchor" href="#📊-사업-수지-분석-및-예산-통제" aria-label="Permalink to &quot;📊 사업 수지 분석 및 예산 통제&quot;">​</a></h3><ul><li>초기 수지표 기반의 예산 편성 및 항목 관리</li><li>예산 대비 실제 집행 실적(Actuals) 실시간 비교</li><li>자금 조달 계획 및 현금 흐름(Cash-flow) 분석</li></ul><h3 id="⚖️-문서-보관소-및-소송-관리" tabindex="-1">⚖️ 문서 보관소 및 소송 관리 <a class="header-anchor" href="#⚖️-문서-보관소-및-소송-관리" aria-label="Permalink to &quot;⚖️ 문서 보관소 및 소송 관리&quot;">​</a></h3><ul><li>프로젝트별 중요 문서 및 법률 자료 통합 관리</li><li>소송 사건별 기일 및 진행 현황 추적</li><li>민원 및 분쟁 처리 히스토리 관리</li></ul><h2 id="ibs의-의미" tabindex="-1">IBS의 의미 <a class="header-anchor" href="#ibs의-의미" aria-label="Permalink to &quot;IBS의 의미&quot;">​</a></h2><p><strong>IBS</strong>는 <strong>I</strong>ntelligent <strong>B</strong>usiness <strong>S</strong>ystem의 약어입니다.</p><p>단순히 업무를 처리하는 프로그램을 넘어, 데이터와 협업을 연결하여 사용자가 더 가치 있는 일에 집중할 수 있도록 돕는 <strong>지능형 업무 플랫폼</strong>입니다.</p><h2 id="우리의-지향점" tabindex="-1">우리의 지향점 <a class="header-anchor" href="#우리의-지향점" aria-label="Permalink to &quot;우리의 지향점&quot;">​</a></h2><p>부동산 개발은 수많은 현장 경험과 정확한 데이터, 그리고 신속한 의사결정이 모여 새로운 공간과 가치를 만들어 가는 과정입니다.</p><p><strong>IBS 워크스페이스</strong>는 반복적인 관리 업무를 줄여, 디벨로퍼들이 사업의 본질인 기획과 분석, 그리고 더 나은 의사결정에 집중할 수 있는 환경을 제공합니다.</p><p>우리는 실제 현장의 경험을 바탕으로, 더 효율적이고 체계적인 부동산 개발 업무 환경을 만들어 갑니다.</p><hr><p>프로그램 설치 및 기본 사용법은 <a href="/intro/getting-started.html">시작하기</a> 문서를 참고하세요.</p>',31)])])}const p=i(t,[["render",n]]);export{g as __pageData,p as default};
